#include <vector>
#include <numeric>

using namespace std;

// Helper function to check parity
// Returns 0 if even, 1 if odd
int get_parity(long long n) {
    return n % 2;
}

/**
 * @brief Calculates the score for each element in the array based on parity differences with subsequent elements.
 * 
 * @param nums The input array of integers.
 * @return vector<long long> The answer array where answer[i] is the score for nums[i].
 */
vector<long long> solve(vector<long long> nums) {
    int n = nums.size();
    if (n <= 1) {
        return {0};
    }

    vector<long long> answer(n, 0);

    // Precompute the total count of odd and even numbers in the entire array
    int total_odd = 0;
    int total_even = 0;
    for (long long x : nums) {
        if (x % 2 != 0) {
            total_odd++;
        } else {
            total_even++;
        }
    }

    // Precompute prefix sums of parity counts
    // prefix_odd[i] = count of odd numbers in nums[0...i-1]
    // prefix_even[i] = count of even numbers in nums[0...i-1]
    vector<int> prefix_odd(n + 1, 0);
    vector<int> prefix_even(n + 1, 0);

    for (int i = 0; i < n; ++i) {
        prefix_odd[i + 1] = prefix_odd[i] + (nums[i] % 2 != 0 ? 1 : 0);
        prefix_even[i + 1] = prefix_even[i] + (nums[i] % 2 == 0 ? 1 : 0);
    }

    for (int i = 0; i < n; ++i) {
        // We are looking at index i. We are interested in j such that i < j < n.
        int remaining_elements = n - 1 - i; // Count of elements strictly after i

        if (remaining_elements <= 0) {
            answer[i] = 0;
            continue;
        }

        // Count of odd/even numbers in nums[i+1...n-1]
        // Total count up to n-1 (which is prefix[n]) minus count up to i (which is prefix[i+1])

        // Total odd in nums[i+1...n-1]
        int suffix_odd = prefix_odd[n] - prefix_odd[i+1];
        // Total even in nums[i+1...n-1]
        int suffix_even = prefix_even[n] - prefix_even[i+1];

        int current_parity = get_parity(nums[i]);
        long long score = 0;

        if (current_parity == 1) { // nums[i] is odd
            // We need j to be even. Count of evens in the suffix.
            score = suffix_even;
        } else { // nums[i] is even
            // We need j to be odd. Count of odds in the suffix.
            score = suffix_odd;
        }

        answer[i] = score;
    }

    return answer;
}
